static int vulkan_dispatch_descriptor_type_from_api(
        uint32_t api_descriptor_type,
        VkDescriptorType *out_type) {
    if (!out_type) return -EINVAL;
    switch ((VkDescriptorType)api_descriptor_type) {
        case VK_DESCRIPTOR_TYPE_STORAGE_BUFFER:
        case VK_DESCRIPTOR_TYPE_STORAGE_BUFFER_DYNAMIC:
            *out_type = VK_DESCRIPTOR_TYPE_STORAGE_BUFFER;
            return 0;
        case VK_DESCRIPTOR_TYPE_UNIFORM_BUFFER:
        case VK_DESCRIPTOR_TYPE_UNIFORM_BUFFER_DYNAMIC:
            *out_type = VK_DESCRIPTOR_TYPE_UNIFORM_BUFFER;
            return 0;
        default:
            return -EOPNOTSUPP;
    }
}

static int vulkan_dispatch_image_descriptor_type_from_api(
        uint32_t api_descriptor_type,
        VkDescriptorType *out_type) {
    if (!out_type) return -EINVAL;
    switch ((VkDescriptorType)api_descriptor_type) {
        case VK_DESCRIPTOR_TYPE_SAMPLER:
        case VK_DESCRIPTOR_TYPE_COMBINED_IMAGE_SAMPLER:
        case VK_DESCRIPTOR_TYPE_SAMPLED_IMAGE:
        case VK_DESCRIPTOR_TYPE_STORAGE_IMAGE:
        case VK_DESCRIPTOR_TYPE_INPUT_ATTACHMENT:
            *out_type = (VkDescriptorType)api_descriptor_type;
            return 0;
        default:
            return -EOPNOTSUPP;
    }
}

static int vulkan_descriptor_type_requires_image_view(VkDescriptorType type) {
    return type == VK_DESCRIPTOR_TYPE_COMBINED_IMAGE_SAMPLER ||
           type == VK_DESCRIPTOR_TYPE_SAMPLED_IMAGE ||
           type == VK_DESCRIPTOR_TYPE_STORAGE_IMAGE ||
           type == VK_DESCRIPTOR_TYPE_INPUT_ATTACHMENT;
}

static int vulkan_descriptor_type_requires_sampler(VkDescriptorType type) {
    return type == VK_DESCRIPTOR_TYPE_SAMPLER ||
           type == VK_DESCRIPTOR_TYPE_COMBINED_IMAGE_SAMPLER;
}

static int vulkan_image_descriptor_layout_valid(
        VkDescriptorType type,
        VkImageLayout layout) {
    switch (type) {
        case VK_DESCRIPTOR_TYPE_STORAGE_IMAGE:
            return layout == VK_IMAGE_LAYOUT_GENERAL;
        case VK_DESCRIPTOR_TYPE_COMBINED_IMAGE_SAMPLER:
        case VK_DESCRIPTOR_TYPE_SAMPLED_IMAGE:
            return layout == VK_IMAGE_LAYOUT_SHADER_READ_ONLY_OPTIMAL ||
                   layout == VK_IMAGE_LAYOUT_GENERAL;
        case VK_DESCRIPTOR_TYPE_SAMPLER:
            return 1;
        case VK_DESCRIPTOR_TYPE_INPUT_ATTACHMENT:
            return layout == VK_IMAGE_LAYOUT_SHADER_READ_ONLY_OPTIMAL ||
                   layout == VK_IMAGE_LAYOUT_GENERAL ||
                   layout == VK_IMAGE_LAYOUT_READ_ONLY_OPTIMAL;
        default:
            return 0;
    }
}

static VkImageUsageFlags vulkan_required_usage_for_image_descriptor(VkDescriptorType type) {
    switch (type) {
        case VK_DESCRIPTOR_TYPE_STORAGE_IMAGE:
            return VK_IMAGE_USAGE_STORAGE_BIT;
        case VK_DESCRIPTOR_TYPE_COMBINED_IMAGE_SAMPLER:
        case VK_DESCRIPTOR_TYPE_SAMPLED_IMAGE:
            return VK_IMAGE_USAGE_SAMPLED_BIT;
        case VK_DESCRIPTOR_TYPE_INPUT_ATTACHMENT:
            return VK_IMAGE_USAGE_INPUT_ATTACHMENT_BIT;
        default:
            return 0;
    }
}

static size_t vulkan_binding_descriptor_range(
        const VulkanDispatchBinding *binding,
        int strict_passthrough) {
    if (!binding) return 0;
    if (strict_passthrough && binding->api_range > 0) {
        return binding->api_range;
    }
    return binding->size;
}

static int vulkan_binding_offset_equals_memory_plus_api_offset(
        const VulkanDispatchBinding *binding) {
    if (!binding || binding->api_memory_offset < 0 || binding->api_offset < 0) {
        return 0;
    }
    const uint64_t memory_offset = (uint64_t)binding->api_memory_offset;
    const uint64_t api_offset = (uint64_t)binding->api_offset;
    if (memory_offset > UINT64_MAX - api_offset) return 0;
    return (uint64_t)binding->offset == memory_offset + api_offset;
}

static int vulkan_binding_descriptor_offset_equals_api_offset(
        const VulkanDispatchBinding *binding,
        size_t binding_descriptor_offset) {
    if (!binding || binding->api_offset < 0) return 0;
    return binding_descriptor_offset == (size_t)binding->api_offset;
}

static int vulkan_binding_gpu_offset_equals_memory_plus_api_offset(
        const VulkanDispatchBinding *binding,
        size_t binding_gpu_offset) {
    if (!binding || binding->api_memory_offset < 0 || binding->api_offset < 0) {
        return 0;
    }
    const uint64_t memory_offset = (uint64_t)binding->api_memory_offset;
    const uint64_t api_offset = (uint64_t)binding->api_offset;
    if (memory_offset > UINT64_MAX - api_offset) return 0;
    return binding_gpu_offset == (size_t)(memory_offset + api_offset);
}

static int vulkan_binding_descriptor_range_matches_api_range(
        const VulkanDispatchBinding *binding,
        size_t descriptor_range,
        int strict_passthrough) {
    if (!binding) return 0;
    if (!strict_passthrough) return descriptor_range == binding->size;
    if (binding->api_range == 0) return descriptor_range == binding->size;
    return descriptor_range == binding->api_range;
}

