static void log_spirv_trace(
        const SpirvTraceSummary *summary,
        const VulkanDispatchBinding *bindings,
        size_t binding_count,
        size_t push_size,
        uint32_t gx,
        uint32_t gy,
        uint32_t gz) {
    if (!summary) return;
    fprintf(stderr,
            "pdocker-gpu-executor: SPIR-V trace valid=%u truncated=%u hash=0x%016llx "
            "magic=0x%08x version=0x%08x words=%u instructions=%u "
            "op_classes={mem:%u,arith:%u,ctrl:%u,barrier:%u} "
            "bound=%u local_size=%u,%u,%u local_size_id=%u,%u,%u "
            "local_size_spec_id=%u,%u,%u "
            "dispatch=%u,%u,%u push=%zu bindings=%zu caps=",
            summary->valid,
            summary->truncated,
            (unsigned long long)summary->hash,
            summary->magic,
            summary->version,
            summary->word_count,
            summary->instruction_count,
            summary->memory_instruction_count,
            summary->arithmetic_instruction_count,
            summary->control_instruction_count,
            summary->barrier_instruction_count,
            summary->bound,
            summary->local_size[0],
            summary->local_size[1],
            summary->local_size[2],
            summary->local_size_id[0],
            summary->local_size_id[1],
            summary->local_size_id[2],
            summary->local_size_spec_id_valid[0] ? summary->local_size_spec_id[0] : UINT32_MAX,
            summary->local_size_spec_id_valid[1] ? summary->local_size_spec_id[1] : UINT32_MAX,
            summary->local_size_spec_id_valid[2] ? summary->local_size_spec_id[2] : UINT32_MAX,
            gx,
            gy,
            gz,
            push_size,
            binding_count);
    for (uint32_t i = 0; i < summary->capability_count; ++i) {
        fprintf(stderr, "%s%s(%u)", i ? "," : "", spirv_capability_name(summary->capabilities[i]), summary->capabilities[i]);
    }
    if (summary->capability_count == 0) fprintf(stderr, "none");
    fprintf(stderr, "\n");
    for (size_t i = 0; i < binding_count; ++i) {
        fprintf(stderr,
                "pdocker-gpu-executor: SPIR-V binding[%zu] binding=%u fd_offset=%lld bytes=%zu\n",
                i,
                bindings[i].binding,
                (long long)bindings[i].offset,
                bindings[i].size);
    }
}

static int spirv_feature_missing(const SpirvTraceSummary *summary, const VulkanRuntime *rt) {
    if (!summary || !rt) return 0;
    if (summary->requires_float16 && !rt->physical_float16_int8.shaderFloat16) return 1;
    if (summary->requires_int64 && !rt->physical_features.shaderInt64) return 1;
    if (summary->requires_storage16 && !rt->physical_storage16.storageBuffer16BitAccess) return 1;
    if (summary->requires_storage8 && !rt->physical_storage8.storageBuffer8BitAccess) return 1;
    if (summary->requires_int8 && !rt->physical_float16_int8.shaderInt8) return 1;
    if (summary->requires_subgroup_arithmetic &&
        (rt->subgroup_properties.supportedOperations & VK_SUBGROUP_FEATURE_ARITHMETIC_BIT) == 0) {
        return 1;
    }
    /*
     * Vulkan has no standalone shaderInt16 feature in this bridge today. The
     * llama path we care about uses 16-bit storage, so record Int16 capability
     * as advisory instead of making every Int16 declaration a hard mismatch.
     */
    return 0;
}

static uint64_t spirv_required_feature_mask(const SpirvTraceSummary *summary) {
    uint64_t mask = 0;
    if (!summary) return mask;
    if (summary->requires_int64) mask |= PDOCKER_VK_FEATURE_SHADER_INT64;
    if (summary->requires_storage16_buffer) mask |= PDOCKER_VK_FEATURE_STORAGE_BUFFER_16;
    if (summary->requires_storage16_uniform) mask |= PDOCKER_VK_FEATURE_UNIFORM_STORAGE_BUFFER_16;
    if (summary->requires_storage16_push_constant) mask |= PDOCKER_VK_FEATURE_STORAGE_PUSH_CONSTANT_16;
    if (summary->requires_storage8_buffer) mask |= PDOCKER_VK_FEATURE_STORAGE_BUFFER_8;
    if (summary->requires_storage8_uniform) mask |= PDOCKER_VK_FEATURE_UNIFORM_STORAGE_BUFFER_8;
    if (summary->requires_storage8_push_constant) mask |= PDOCKER_VK_FEATURE_STORAGE_PUSH_CONSTANT_8;
    if (summary->requires_float16) mask |= PDOCKER_VK_FEATURE_SHADER_FLOAT16;
    if (summary->requires_int8) mask |= PDOCKER_VK_FEATURE_SHADER_INT8;
    return mask;
}

static void write_feature_mask_names(FILE *out, uint64_t mask) {
    if (!out) return;
    int first = 1;
#define WRITE_FEATURE_NAME(bit, name) do { \
        if (mask & (bit)) { \
            fprintf(out, "%s\"%s\"", first ? "" : ",", name); \
            first = 0; \
        } \
    } while (0)
    WRITE_FEATURE_NAME(PDOCKER_VK_FEATURE_SHADER_INT64, "shaderInt64");
    WRITE_FEATURE_NAME(PDOCKER_VK_FEATURE_STORAGE_BUFFER_16, "storageBuffer16BitAccess");
    WRITE_FEATURE_NAME(PDOCKER_VK_FEATURE_UNIFORM_STORAGE_BUFFER_16, "uniformAndStorageBuffer16BitAccess");
    WRITE_FEATURE_NAME(PDOCKER_VK_FEATURE_STORAGE_PUSH_CONSTANT_16, "storagePushConstant16");
    WRITE_FEATURE_NAME(PDOCKER_VK_FEATURE_STORAGE_BUFFER_8, "storageBuffer8BitAccess");
    WRITE_FEATURE_NAME(PDOCKER_VK_FEATURE_UNIFORM_STORAGE_BUFFER_8, "uniformAndStorageBuffer8BitAccess");
    WRITE_FEATURE_NAME(PDOCKER_VK_FEATURE_STORAGE_PUSH_CONSTANT_8, "storagePushConstant8");
    WRITE_FEATURE_NAME(PDOCKER_VK_FEATURE_SHADER_FLOAT16, "shaderFloat16");
    WRITE_FEATURE_NAME(PDOCKER_VK_FEATURE_SHADER_INT8, "shaderInt8");
#undef WRITE_FEATURE_NAME
}

static void write_spirv_feature_report(
        FILE *out,
        const SpirvTraceSummary *summary,
        const VulkanRuntime *rt,
        const VulkanDispatchOptions *options) {
    if (!out || !summary) return;
    const int missing_float16 = summary->requires_float16 && (!rt || !rt->physical_float16_int8.shaderFloat16);
    const int missing_int64 = summary->requires_int64 && (!rt || !rt->physical_features.shaderInt64);
    const int missing_storage16 = summary->requires_storage16 && (!rt || !rt->physical_storage16.storageBuffer16BitAccess);
    const int missing_storage8 = summary->requires_storage8 && (!rt || !rt->physical_storage8.storageBuffer8BitAccess);
    const int missing_int8 = summary->requires_int8 && (!rt || !rt->physical_float16_int8.shaderInt8);
    const int missing_subgroup_arithmetic = summary->requires_subgroup_arithmetic &&
        (!rt || (rt->subgroup_properties.supportedOperations & VK_SUBGROUP_FEATURE_ARITHMETIC_BIT) == 0);
    const uint64_t required_mask = spirv_required_feature_mask(summary);
    const uint64_t requested_mask = options ? options->requested_feature_mask : 0;
    const int requested_mask_present = options && options->has_requested_feature_mask;
    const uint64_t requested_missing_mask = requested_mask_present ? (required_mask & ~requested_mask) : 0;
    fprintf(out,
            "\"spirv_feature_requirements\":{"
            "\"float16\":%s,\"int16\":%s,\"int8\":%s,\"int64\":%s,"
            "\"storage16\":%s,\"storage8\":%s,\"subgroup_arithmetic\":%s},"
            "\"spirv_required_feature_mask\":\"0x%016llx\","
            "\"spirv_requested_feature_missing_mask\":\"0x%016llx\","
            "\"spirv_requested_feature_mismatches\":[",
            summary->requires_float16 ? "true" : "false",
            summary->requires_int16 ? "true" : "false",
            summary->requires_int8 ? "true" : "false",
            summary->requires_int64 ? "true" : "false",
            summary->requires_storage16 ? "true" : "false",
            summary->requires_storage8 ? "true" : "false",
            summary->requires_subgroup_arithmetic ? "true" : "false",
            (unsigned long long)required_mask,
            (unsigned long long)requested_missing_mask);
    write_feature_mask_names(out, requested_missing_mask);
    fprintf(out,
            "],"
            "\"spirv_feature_mismatch\":%s,"
            "\"spirv_feature_mismatches\":[",
            spirv_feature_missing(summary, rt) ? "true" : "false");
    int first = 1;
#define WRITE_MISMATCH(name, cond) do { \
        if (cond) { \
            fprintf(out, "%s\"%s\"", first ? "" : ",", name); \
            first = 0; \
        } \
    } while (0)
    WRITE_MISMATCH("float16", missing_float16);
    WRITE_MISMATCH("int64", missing_int64);
    WRITE_MISMATCH("storage16", missing_storage16);
    WRITE_MISMATCH("storage8", missing_storage8);
    WRITE_MISMATCH("int8", missing_int8);
    WRITE_MISMATCH("subgroup_arithmetic", missing_subgroup_arithmetic);
#undef WRITE_MISMATCH
    fprintf(out, "]");
}

static void write_vulkan_specialization_report(
        FILE *out,
        const VulkanDispatchSpecialization *specializations,
        size_t specialization_count,
        const uint8_t *specialization_data,
        size_t specialization_data_size) {
    fprintf(out, "\"specialization_entries\":[");
    for (size_t i = 0; i < specialization_count; ++i) {
        uint64_t value = specialization_value_u64(
            specialization_data,
            specialization_data_size,
            &specializations[i]);
        fprintf(out,
                "%s{\"constant_id\":%u,\"offset\":%u,\"size\":%zu,\"value_u64\":%llu}",
                i ? "," : "",
                specializations[i].constant_id,
                specializations[i].offset,
                specializations[i].size,
                (unsigned long long)value);
    }
    fprintf(out, "]");
}

static void resolve_spirv_local_size(
        const SpirvTraceSummary *summary,
        const VulkanDispatchSpecialization *specializations,
        size_t specialization_count,
        const uint8_t *specialization_data,
        size_t specialization_data_size,
        uint64_t out[3]) {
    if (!out) return;
    out[0] = out[1] = out[2] = 1;
    if (!summary) return;
    for (uint32_t i = 0; i < 3; ++i) {
        uint64_t value = summary->local_size[i] ? summary->local_size[i] : 1;
        if (summary->local_size_spec_id_valid[i]) {
            uint64_t spec_value = 0;
            if (specialization_value_for_id(specializations,
                                            specialization_count,
                                            specialization_data,
                                            specialization_data_size,
                                            summary->local_size_spec_id[i],
                                            &spec_value)) {
                value = spec_value;
            }
        } else if (summary->workgroup_size_spec_id_valid[i]) {
            uint64_t spec_value = 0;
            if (specialization_value_for_id(specializations,
                                            specialization_count,
                                            specialization_data,
                                            specialization_data_size,
                                            summary->workgroup_size_spec_id[i],
                                            &spec_value)) {
                value = spec_value;
            }
        }
        out[i] = value;
    }
}

static int spirv_local_invocation_count(const uint64_t local_size[3], uint64_t *out) {
    if (out) *out = 0;
    if (!local_size) return 0;
    uint64_t product = 1;
    for (uint32_t i = 0; i < 3; ++i) {
        if (local_size[i] == 0 || local_size[i] > 1024) return 0;
        if (product > UINT64_MAX / local_size[i]) return 0;
        product *= local_size[i];
        if (product > 1024) return 0;
    }
    if (out) *out = product;
    return product >= 1 && product <= 1024;
}

static int spirv_local_size_consistent(
        const SpirvTraceSummary *summary,
        const VulkanDispatchSpecialization *specializations,
        size_t specialization_count,
        const uint8_t *specialization_data,
        size_t specialization_data_size) {
    if (!summary || !summary->valid) return 1;
    if (!summary->local_size_id[0] && !summary->local_size_id[1] &&
        !summary->local_size_id[2] &&
        !summary->workgroup_size_spec_id_valid[0] &&
        !summary->workgroup_size_spec_id_valid[1] &&
        !summary->workgroup_size_spec_id_valid[2]) {
        return 1;
    }
    uint64_t resolved[3];
    resolve_spirv_local_size(summary,
                             specializations,
                             specialization_count,
                             specialization_data,
                             specialization_data_size,
                             resolved);
    for (uint32_t i = 0; i < 3; ++i) {
        if (summary->local_size[i] && summary->local_size[i] != resolved[i]) {
            return 0;
        }
    }
    uint64_t invocations = 0;
    return spirv_local_invocation_count(resolved, &invocations);
}

static void write_spirv_execution_report(
        FILE *out,
        const SpirvTraceSummary *summary,
        const VulkanDispatchSpecialization *specializations,
        size_t specialization_count,
        const uint8_t *specialization_data,
        size_t specialization_data_size,
        const uint8_t *push,
        size_t push_size) {
    if (!out || !summary) return;
    uint64_t resolved_local_size[3];
    resolve_spirv_local_size(summary,
                             specializations,
                             specialization_count,
                             specialization_data,
                             specialization_data_size,
                             resolved_local_size);
    const int local_size_consistent =
        spirv_local_size_consistent(summary,
                                    specializations,
                                    specialization_count,
                                    specialization_data,
                                    specialization_data_size);
    fprintf(out,
            "\"push_bytes\":%zu,"
            "\"push_u32\":[",
            push_size);
    size_t push_u32_count = push && push_size >= sizeof(uint32_t)
        ? push_size / sizeof(uint32_t)
        : 0;
    if (push_u32_count > 32) push_u32_count = 32;
    for (size_t i = 0; i < push_u32_count; ++i) {
        uint32_t value = 0;
        memcpy(&value, push + i * sizeof(uint32_t), sizeof(value));
        fprintf(out, "%s%u", i ? "," : "", value);
    }
    fprintf(out,
            "],"
            "\"spirv_hash\":\"0x%016llx\","
            "\"spirv_valid\":%s,\"spirv_truncated\":%u,"
            "\"spirv_words\":%u,"
            "\"spirv_instruction_count\":%u,"
            "\"spirv_op_class_counts\":{\"memory\":%u,\"arithmetic\":%u,\"control\":%u,\"barrier\":%u},"
            "\"spirv_local_size\":[%u,%u,%u],"
            "\"spirv_local_size_id\":[%u,%u,%u],"
            "\"spirv_local_size_spec_id\":[%u,%u,%u],"
            "\"spirv_workgroup_size_spec_id\":[%u,%u,%u],"
            "\"spirv_local_size_resolved\":[%llu,%llu,%llu],"
            "\"spirv_local_size_consistent\":%s,",
            (unsigned long long)summary->hash,
            summary->valid ? "true" : "false",
            summary->truncated,
            summary->word_count,
            summary->instruction_count,
            summary->memory_instruction_count,
            summary->arithmetic_instruction_count,
            summary->control_instruction_count,
            summary->barrier_instruction_count,
            summary->local_size[0],
            summary->local_size[1],
            summary->local_size[2],
            summary->local_size_id[0],
            summary->local_size_id[1],
            summary->local_size_id[2],
            summary->local_size_spec_id_valid[0] ? summary->local_size_spec_id[0] : UINT32_MAX,
            summary->local_size_spec_id_valid[1] ? summary->local_size_spec_id[1] : UINT32_MAX,
            summary->local_size_spec_id_valid[2] ? summary->local_size_spec_id[2] : UINT32_MAX,
            summary->workgroup_size_spec_id_valid[0] ? summary->workgroup_size_spec_id[0] : UINT32_MAX,
            summary->workgroup_size_spec_id_valid[1] ? summary->workgroup_size_spec_id[1] : UINT32_MAX,
            summary->workgroup_size_spec_id_valid[2] ? summary->workgroup_size_spec_id[2] : UINT32_MAX,
            (unsigned long long)resolved_local_size[0],
            (unsigned long long)resolved_local_size[1],
            (unsigned long long)resolved_local_size[2],
            local_size_consistent ? "true" : "false");
    write_vulkan_specialization_report(out,
                                       specializations,
                                       specialization_count,
                                       specialization_data,
                                       specialization_data_size);
}

static void write_vulkan_limits_report(FILE *out, const VulkanRuntime *rt) {
    if (!out || !rt) return;
    const VkPhysicalDeviceLimits *limits = &rt->physical_properties.limits;
    fprintf(out,
            "\"android_vulkan_device\":{"
            "\"api\":\"%u.%u\",\"deviceName\":\"",
            VK_API_VERSION_MAJOR(rt->api_version),
            VK_API_VERSION_MINOR(rt->api_version));
    const char *name = rt->physical_properties.deviceName;
    for (size_t i = 0; name && name[i]; ++i) {
        unsigned char ch = (unsigned char)name[i];
        if (ch == '"' || ch == '\\') fputc('\\', out);
        if (ch >= 0x20 && ch < 0x7f) fputc((int)ch, out);
    }
    fprintf(out,
            "\",\"vendorID\":%u,\"deviceID\":%u,"
            "\"limits\":{"
            "\"maxPushConstantsSize\":%u,"
            "\"maxComputeSharedMemorySize\":%u,"
            "\"maxPerStageDescriptorStorageBuffers\":%u,"
            "\"maxDescriptorSetStorageBuffers\":%u,"
            "\"maxBoundDescriptorSets\":%u,"
            "\"maxComputeWorkGroupInvocations\":%u,"
            "\"maxComputeWorkGroupSize\":[%u,%u,%u],"
            "\"maxComputeWorkGroupCount\":[%u,%u,%u]}}",
            rt->physical_properties.vendorID,
            rt->physical_properties.deviceID,
            limits->maxPushConstantsSize,
            limits->maxComputeSharedMemorySize,
            limits->maxPerStageDescriptorStorageBuffers,
            limits->maxDescriptorSetStorageBuffers,
            limits->maxBoundDescriptorSets,
            limits->maxComputeWorkGroupInvocations,
            limits->maxComputeWorkGroupSize[0],
            limits->maxComputeWorkGroupSize[1],
            limits->maxComputeWorkGroupSize[2],
            limits->maxComputeWorkGroupCount[0],
            limits->maxComputeWorkGroupCount[1],
            limits->maxComputeWorkGroupCount[2]);
}

static void write_json_string_literal(FILE *out, const char *value) {
    if (!out) return;
    fputc('"', out);
    for (size_t i = 0; value && value[i]; ++i) {
        unsigned char ch = (unsigned char)value[i];
        if (ch == '"' || ch == '\\') {
            fputc('\\', out);
            fputc((int)ch, out);
        } else if (ch >= 0x20 && ch < 0x7f) {
            fputc((int)ch, out);
        }
    }
    fputc('"', out);
}

static int create_vulkan_buffer_with_usage(
        VkPhysicalDevice physical_device,
        VkDevice device,
        size_t bytes,
        VkBufferUsageFlags usage,
        const void *initial,
        VulkanVectorBuffer *out) {
    memset(out, 0, sizeof(*out));
    if (bytes == 0) return -EINVAL;
    VkBufferCreateInfo bci = {
        .sType = VK_STRUCTURE_TYPE_BUFFER_CREATE_INFO,
        .size = (VkDeviceSize)bytes,
        .usage = usage,
        .sharingMode = VK_SHARING_MODE_EXCLUSIVE,
    };
    VkResult rc = vkCreateBuffer(device, &bci, NULL, &out->buffer);
    if (rc != VK_SUCCESS) return -10;
    VkMemoryRequirements req;
    vkGetBufferMemoryRequirements(device, out->buffer, &req);
    uint32_t memory_type = find_vulkan_memory_type(
        physical_device,
        req.memoryTypeBits,
        VK_MEMORY_PROPERTY_HOST_VISIBLE_BIT | VK_MEMORY_PROPERTY_HOST_COHERENT_BIT);
    if (memory_type == UINT32_MAX) return -11;
    VkMemoryAllocateInfo mai = {
        .sType = VK_STRUCTURE_TYPE_MEMORY_ALLOCATE_INFO,
        .allocationSize = req.size,
        .memoryTypeIndex = memory_type,
    };
    rc = vkAllocateMemory(device, &mai, NULL, &out->memory);
    if (rc != VK_SUCCESS) return -12;
    rc = vkBindBufferMemory(device, out->buffer, out->memory, 0);
    if (rc != VK_SUCCESS) return -13;
    rc = vkMapMemory(device, out->memory, 0, (VkDeviceSize)bytes, 0, &out->map);
    if (rc != VK_SUCCESS || !out->map) return -14;
    out->size = bytes;
    if (initial) memcpy(out->map, initial, bytes);
    return 0;
}

static int create_vulkan_vector_buffer(VkPhysicalDevice physical_device, VkDevice device, size_t bytes, const void *initial, VulkanVectorBuffer *out) {
    return create_vulkan_buffer_with_usage(
        physical_device,
        device,
        bytes,
        VK_BUFFER_USAGE_STORAGE_BUFFER_BIT,
        initial,
        out);
}

static void destroy_vulkan_vector_buffer(VkDevice device, VulkanVectorBuffer *buf) {
    if (!buf) return;
    if (buf->map) vkUnmapMemory(device, buf->memory);
    if (buf->buffer) vkDestroyBuffer(device, buf->buffer, NULL);
    if (buf->memory) vkFreeMemory(device, buf->memory, NULL);
    memset(buf, 0, sizeof(*buf));
}

