static int vulkan_vector_staging_offset(
        const VulkanVectorBuffer *buffer,
        size_t descriptor_offset,
        size_t byte_size,
        size_t *out_offset) {
    if (!buffer || !out_offset) return -EINVAL;
    if (!buffer->device_local_staged) {
        *out_offset = descriptor_offset;
        return 0;
    }
    if (descriptor_offset < buffer->staging_base) return -EINVAL;
    const size_t local = descriptor_offset - buffer->staging_base;
    if (local > buffer->size || byte_size > buffer->size - local) return -EINVAL;
    *out_offset = local;
    return 0;
}

static int find_strict_memory_object(
        const VulkanStrictMemoryObject *objects,
        size_t count,
        uint64_t memory_id) {
    for (size_t i = 0; i < count; ++i) {
        if (objects[i].memory_id == memory_id) return (int)i;
    }
    return -1;
}

static int find_strict_buffer_object(
        const VulkanStrictBufferObject *objects,
        size_t count,
        uint64_t buffer_id) {
    for (size_t i = 0; i < count; ++i) {
        if (objects[i].buffer_id == buffer_id) return (int)i;
    }
    return -1;
}

static int checked_u64_add3(uint64_t a, uint64_t b, uint64_t c, uint64_t *out);

static int checked_u64_to_off_t(uint64_t value, off_t *out) {
    if (!out) return -EINVAL;
    if (value > (uint64_t)LLONG_MAX) return -EOVERFLOW;
    *out = (off_t)value;
    return 0;
}

static int find_image_memory_object(
        const VulkanDispatchImageMemoryObject *objects,
        size_t count,
        uint32_t resource_index) {
    for (size_t i = 0; i < count; ++i) {
        if (objects[i].resource_index == resource_index) return (int)i;
    }
    return -1;
}

static int checked_mul_u64_executor(uint64_t a, uint64_t b, uint64_t *out) {
    if (!out) return 0;
    if (a != 0 && b > UINT64_MAX / a) return 0;
    *out = a * b;
    return 1;
}

static int checked_add_u64_executor(uint64_t a, uint64_t b, uint64_t *out) {
    if (!out || a > UINT64_MAX - b) return 0;
    *out = a + b;
    return 1;
}

static uint32_t vulkan_format_bytes_per_pixel_conservative(VkFormat format) {
    switch (format) {
        case VK_FORMAT_R8_UNORM:
        case VK_FORMAT_R8_SNORM:
        case VK_FORMAT_R8_UINT:
        case VK_FORMAT_R8_SINT:
            return 1;
        case VK_FORMAT_R8G8_UNORM:
        case VK_FORMAT_R8G8_SNORM:
        case VK_FORMAT_R8G8_UINT:
        case VK_FORMAT_R8G8_SINT:
        case VK_FORMAT_R16_SFLOAT:
        case VK_FORMAT_R16_UINT:
        case VK_FORMAT_R16_SINT:
            return 2;
        case VK_FORMAT_R8G8B8A8_UNORM:
        case VK_FORMAT_R8G8B8A8_SNORM:
        case VK_FORMAT_R8G8B8A8_UINT:
        case VK_FORMAT_R8G8B8A8_SINT:
        case VK_FORMAT_B8G8R8A8_UNORM:
        case VK_FORMAT_R16G16_SFLOAT:
        case VK_FORMAT_R32_SFLOAT:
        case VK_FORMAT_R32_UINT:
        case VK_FORMAT_R32_SINT:
            return 4;
        case VK_FORMAT_R16G16B16A16_SFLOAT:
        case VK_FORMAT_R32G32_SFLOAT:
        case VK_FORMAT_R32G32_UINT:
        case VK_FORMAT_R32G32_SINT:
            return 8;
        case VK_FORMAT_R32G32B32A32_SFLOAT:
        case VK_FORMAT_R32G32B32A32_UINT:
        case VK_FORMAT_R32G32B32A32_SINT:
            return 16;
        default:
            return 16;
    }
}

static uint32_t vulkan_format_bytes_per_pixel_for_aspect(
        VkFormat format,
        VkImageAspectFlags aspect_mask) {
    if (aspect_mask == VK_IMAGE_ASPECT_DEPTH_BIT) {
        switch (format) {
            case VK_FORMAT_D16_UNORM:
            case VK_FORMAT_D16_UNORM_S8_UINT:
                return 2;
            case VK_FORMAT_X8_D24_UNORM_PACK32:
            case VK_FORMAT_D24_UNORM_S8_UINT:
            case VK_FORMAT_D32_SFLOAT:
            case VK_FORMAT_D32_SFLOAT_S8_UINT:
                return 4;
            default:
                return 0;
        }
    }
    if (aspect_mask == VK_IMAGE_ASPECT_STENCIL_BIT) {
        switch (format) {
            case VK_FORMAT_S8_UINT:
            case VK_FORMAT_D16_UNORM_S8_UINT:
            case VK_FORMAT_D24_UNORM_S8_UINT:
            case VK_FORMAT_D32_SFLOAT_S8_UINT:
                return 1;
            default:
                return 0;
        }
    }
    if (aspect_mask == VK_IMAGE_ASPECT_COLOR_BIT) {
        return vulkan_format_bytes_per_pixel_conservative(format);
    }
    return 0;
}

static int vulkan_image_mip_extent(
        const VulkanDispatchImageObject *image,
        uint32_t mip_level,
        VkExtent3D *out) {
    if (!image || !out || mip_level >= image->mip_levels) return 0;
    out->width = image->extent.width >> mip_level;
    out->height = image->extent.height >> mip_level;
    out->depth = image->extent.depth >> mip_level;
    if (out->width == 0) out->width = 1;
    if (out->height == 0) out->height = 1;
    if (out->depth == 0) out->depth = 1;
    return 1;
}

static int vulkan_image_tight_mip_size(
        const VulkanDispatchImageObject *image,
        uint32_t mip_level,
        uint64_t *out_size) {
    VkExtent3D extent;
    if (!vulkan_image_mip_extent(image, mip_level, &extent) || !out_size) return 0;
    uint64_t pixels = 0;
    if (!checked_mul_u64_executor(extent.width, extent.height, &pixels)) return 0;
    if (!checked_mul_u64_executor(pixels, extent.depth, &pixels)) return 0;
    if (!checked_mul_u64_executor(
            pixels,
            vulkan_format_bytes_per_pixel_conservative(image->format),
            out_size)) return 0;
    return 1;
}

static int vulkan_image_tight_layer_stride(
        const VulkanDispatchImageObject *image,
        uint64_t *out_stride) {
    if (!image || !out_stride) return 0;
    uint64_t stride = 0;
    for (uint32_t mip = 0; mip < image->mip_levels; ++mip) {
        uint64_t mip_size = 0;
        if (!vulkan_image_tight_mip_size(image, mip, &mip_size)) return 0;
        if (!checked_add_u64_executor(stride, mip_size, &stride)) return 0;
    }
    *out_stride = stride;
    return 1;
}

static int vulkan_image_tight_subresource_offset(
        const VulkanDispatchImageObject *image,
        uint32_t mip_level,
        uint32_t array_layer,
        uint64_t *out_offset) {
    if (!image || !out_offset || mip_level >= image->mip_levels ||
        array_layer >= image->array_layers) {
        return 0;
    }
    uint64_t layer_stride = 0;
    if (!vulkan_image_tight_layer_stride(image, &layer_stride)) return 0;
    uint64_t offset = 0;
    if (!checked_mul_u64_executor(layer_stride, array_layer, &offset)) return 0;
    for (uint32_t mip = 0; mip < mip_level; ++mip) {
        uint64_t mip_size = 0;
        if (!vulkan_image_tight_mip_size(image, mip, &mip_size)) return 0;
        if (!checked_add_u64_executor(offset, mip_size, &offset)) return 0;
    }
    *out_offset = offset;
    return 1;
}

static int vulkan_image_tight_mip_size_for_aspect(
        const VulkanDispatchImageObject *image,
        uint32_t mip_level,
        VkImageAspectFlags aspect_mask,
        uint64_t *out_size) {
    VkExtent3D extent;
    if (!vulkan_image_mip_extent(image, mip_level, &extent) || !out_size) return 0;
    uint32_t bpp = vulkan_format_bytes_per_pixel_for_aspect(image->format, aspect_mask);
    if (bpp == 0) return 0;
    uint64_t pixels = 0;
    if (!checked_mul_u64_executor(extent.width, extent.height, &pixels)) return 0;
    if (!checked_mul_u64_executor(pixels, extent.depth, &pixels)) return 0;
    if (!checked_mul_u64_executor(pixels, bpp, out_size)) return 0;
    return 1;
}

static int vulkan_image_tight_layer_stride_for_aspect(
        const VulkanDispatchImageObject *image,
        VkImageAspectFlags aspect_mask,
        uint64_t *out_stride) {
    if (!image || !out_stride) return 0;
    uint64_t stride = 0;
    for (uint32_t mip = 0; mip < image->mip_levels; ++mip) {
        uint64_t mip_size = 0;
        if (!vulkan_image_tight_mip_size_for_aspect(image, mip, aspect_mask, &mip_size)) return 0;
        if (!checked_add_u64_executor(stride, mip_size, &stride)) return 0;
    }
    *out_stride = stride;
    return 1;
}

static int vulkan_image_tight_subresource_offset_for_aspect(
        const VulkanDispatchImageObject *image,
        uint32_t mip_level,
        uint32_t array_layer,
        VkImageAspectFlags aspect_mask,
        uint64_t *out_offset) {
    if (!image || !out_offset || mip_level >= image->mip_levels ||
        array_layer >= image->array_layers) {
        return 0;
    }
    uint64_t layer_stride = 0;
    if (!vulkan_image_tight_layer_stride_for_aspect(image, aspect_mask, &layer_stride)) return 0;
    uint64_t offset = 0;
    if (!checked_mul_u64_executor(layer_stride, array_layer, &offset)) return 0;
    for (uint32_t mip = 0; mip < mip_level; ++mip) {
        uint64_t mip_size = 0;
        if (!vulkan_image_tight_mip_size_for_aspect(image, mip, aspect_mask, &mip_size)) return 0;
        if (!checked_add_u64_executor(offset, mip_size, &offset)) return 0;
    }
    *out_offset = offset;
    return 1;
}

static int vulkan_image_tight_copy_size_for_aspect(
        const VulkanDispatchImageObject *image,
        uint32_t mip_level,
        uint32_t layer_count,
        VkImageAspectFlags aspect_mask,
        uint64_t *out_size) {
    if (!image || !out_size || layer_count == 0) return 0;
    uint64_t mip_size = 0;
    if (!vulkan_image_tight_mip_size_for_aspect(image, mip_level, aspect_mask, &mip_size)) return 0;
    if (!checked_mul_u64_executor(mip_size, layer_count, out_size)) return 0;
    return 1;
}

static void destroy_vulkan_dispatch_image_objects(
        VkDevice device,
        VulkanDispatchImageMemoryObject *memories,
        size_t memory_count,
        VulkanDispatchImageObject *images,
        size_t image_count,
        VulkanDispatchImageViewObject *views,
        size_t view_count,
        VulkanDispatchSamplerObject *samplers,
        size_t sampler_count) {
    if (views) {
        for (size_t i = 0; i < view_count; ++i) {
            if (views[i].view) vkDestroyImageView(device, views[i].view, NULL);
            memset(&views[i], 0, sizeof(views[i]));
        }
    }
    if (samplers) {
        for (size_t i = 0; i < sampler_count; ++i) {
            if (samplers[i].sampler) vkDestroySampler(device, samplers[i].sampler, NULL);
            memset(&samplers[i], 0, sizeof(samplers[i]));
        }
    }
    if (images) {
        for (size_t i = 0; i < image_count; ++i) {
            destroy_vulkan_vector_buffer(device, &images[i].staging);
            if (images[i].image) vkDestroyImage(device, images[i].image, NULL);
            memset(&images[i], 0, sizeof(images[i]));
        }
    }
    if (memories) {
        for (size_t i = 0; i < memory_count; ++i) {
            if (memories[i].map) vkUnmapMemory(device, memories[i].memory);
            if (memories[i].memory) vkFreeMemory(device, memories[i].memory, NULL);
            memset(&memories[i], 0, sizeof(memories[i]));
        }
    }
}

static int materialize_vulkan_dispatch_images(
        VkPhysicalDevice physical_device,
        VkDevice device,
        const VulkanDispatchImageDescriptor *image_descriptors,
        size_t image_descriptor_count,
        const VulkanDispatchV5ObjectTables *object_tables,
        VulkanDispatchImageMemoryObject *memories,
        size_t *memory_count,
        VulkanDispatchImageObject *images,
        size_t *image_count,
        VulkanDispatchImageViewObject *views,
        size_t *view_count,
        VulkanDispatchSamplerObject *samplers,
        size_t *sampler_count) {
    if (!memory_count || !image_count || !view_count || !sampler_count) return -EINVAL;
    *memory_count = 0;
    *image_count = 0;
    *view_count = 0;
    *sampler_count = 0;
    if (image_descriptor_count == 0 &&
        (!object_tables ||
         (object_tables->image_count == 0 &&
          object_tables->image_view_count == 0 &&
          object_tables->sampler_count == 0))) {
        return 0;
    }
    if ((image_descriptor_count > 0 && !image_descriptors) ||
        !object_tables || !object_tables->resources ||
        !object_tables->passed_fds || !object_tables->images ||
        !object_tables->image_views || !memories || !images || !views || !samplers) {
        return -EINVAL;
    }
    if (object_tables->image_count > PDOCKER_GPU_MAX_VULKAN_BINDINGS ||
        object_tables->image_view_count > PDOCKER_GPU_MAX_VULKAN_BINDINGS ||
        object_tables->sampler_count > PDOCKER_GPU_MAX_VULKAN_BINDINGS) {
        return -E2BIG;
    }

    for (size_t i = 0; i < object_tables->image_count; ++i) {
        const PdockerGpuVulkanDispatchV5ImageEntry *src = &object_tables->images[i];
        if (src->memory_resource_index >= object_tables->resource_count) return -EPROTO;
        const PdockerGpuVulkanDispatchV5ResourceEntry *mem =
            &object_tables->resources[src->memory_resource_index];
        if (mem->resource_type != PDOCKER_GPU_V5_RESOURCE_TYPE_MEMORY ||
            !(mem->resource_flags & PDOCKER_GPU_V5_RESOURCE_FLAG_HOST_FD_BACKED) ||
            mem->fd_index >= object_tables->passed_fd_count ||
            object_tables->passed_fds[mem->fd_index] < 0 ||
            mem->size > (uint64_t)SIZE_MAX ||
            src->memory_offset > mem->size ||
            src->memory_size > mem->size - src->memory_offset) {
            return -EPROTO;
        }
        if (src->extent_width == 0 || src->extent_height == 0 ||
            src->extent_depth == 0 || src->mip_levels == 0 ||
            src->array_layers == 0 || src->memory_size > (uint64_t)SIZE_MAX) {
            return -EPROTO;
        }
        if (src->initial_layout != VK_IMAGE_LAYOUT_UNDEFINED &&
            src->initial_layout != VK_IMAGE_LAYOUT_PREINITIALIZED) {
            return -EPROTO;
        }
        if (src->tiling == VK_IMAGE_TILING_OPTIMAL) {
            if (src->initial_layout == VK_IMAGE_LAYOUT_PREINITIALIZED) {
                return -ENOTSUP;
            }
        } else if (src->tiling != VK_IMAGE_TILING_LINEAR) {
            return -ENOTSUP;
        }
        int mem_index = find_image_memory_object(
            memories, *memory_count, src->memory_resource_index);
        if (mem_index < 0) {
            if (*memory_count >= PDOCKER_GPU_MAX_VULKAN_BINDINGS) return -E2BIG;
            mem_index = (int)(*memory_count)++;
            memories[mem_index].resource_index = src->memory_resource_index;
            memories[mem_index].memory_id = mem->resource_id;
            memories[mem_index].fd = object_tables->passed_fds[mem->fd_index];
            memories[mem_index].size = (size_t)mem->size;
            memories[mem_index].allocation_size = (size_t)mem->size;
            memories[mem_index].external_offset = mem->external_offset;
            memories[mem_index].memory_type_bits = UINT32_MAX;
        }
        if (*image_count >= PDOCKER_GPU_MAX_VULKAN_BINDINGS) return -E2BIG;
        VulkanDispatchImageObject *dst = &images[(*image_count)++];
        memset(dst, 0, sizeof(*dst));
        dst->image_id = src->image_id;
        dst->source_index = (uint32_t)i;
        dst->memory_resource_index = src->memory_resource_index;
        dst->memory_object_index = (size_t)mem_index;
        dst->memory_offset = (VkDeviceSize)src->memory_offset;
        dst->memory_size = (VkDeviceSize)src->memory_size;
        dst->current_layout = (VkImageLayout)src->initial_layout;
        dst->extent = (VkExtent3D){
            .width = src->extent_width,
            .height = src->extent_height,
            .depth = src->extent_depth,
        };
        dst->format = (VkFormat)src->format;
        dst->tiling = (VkImageTiling)src->tiling;
        dst->usage = (VkImageUsageFlags)src->usage;
        dst->array_layers = src->array_layers;
        dst->mip_levels = src->mip_levels;
        dst->requires_staging = src->tiling == VK_IMAGE_TILING_OPTIMAL;
        dst->upload_pending = dst->requires_staging;
        VkImageCreateInfo ici = {
            .sType = VK_STRUCTURE_TYPE_IMAGE_CREATE_INFO,
            .flags = (VkImageCreateFlags)src->create_flags,
            .imageType = (VkImageType)src->image_type,
            .format = (VkFormat)src->format,
            .extent = dst->extent,
            .mipLevels = src->mip_levels,
            .arrayLayers = src->array_layers,
            .samples = (VkSampleCountFlagBits)src->samples,
            .tiling = (VkImageTiling)src->tiling,
            .usage = dst->requires_staging
                ? ((VkImageUsageFlags)src->usage |
                   VK_IMAGE_USAGE_TRANSFER_DST_BIT |
                   VK_IMAGE_USAGE_TRANSFER_SRC_BIT)
                : (VkImageUsageFlags)src->usage,
            .sharingMode = (VkSharingMode)src->sharing_mode,
            .initialLayout = (VkImageLayout)src->initial_layout,
        };
        VkResult rc = vkCreateImage(device, &ici, NULL, &dst->image);
        if (rc != VK_SUCCESS) return -EIO;
        vkGetImageMemoryRequirements(device, dst->image, &dst->requirements);
        VulkanDispatchImageMemoryObject *memory = &memories[mem_index];
        memory->memory_type_bits &= dst->requirements.memoryTypeBits;
        if (dst->memory_offset % dst->requirements.alignment != 0) return -EINVAL;
        if (dst->memory_offset > (VkDeviceSize)memory->size ||
            dst->requirements.size > (VkDeviceSize)memory->size - dst->memory_offset) {
            return -ERANGE;
        }
        if (dst->memory_size < dst->requirements.size) return -ERANGE;
        uint64_t native_end = 0;
        if (checked_u64_add3((uint64_t)dst->memory_offset,
                             (uint64_t)dst->requirements.size,
                             0,
                             &native_end) != 0 ||
            native_end > (uint64_t)SIZE_MAX) {
            return -EOVERFLOW;
        }
        if ((size_t)native_end > memory->allocation_size) {
            memory->allocation_size = (size_t)native_end;
        }
        if (!dst->requires_staging) {
            memory->needs_host_map = 1;
        }
    }

    for (size_t m = 0; m < *memory_count; ++m) {
        VkMemoryPropertyFlags required_flags = memories[m].needs_host_map
            ? (VK_MEMORY_PROPERTY_HOST_VISIBLE_BIT | VK_MEMORY_PROPERTY_HOST_COHERENT_BIT)
            : VK_MEMORY_PROPERTY_DEVICE_LOCAL_BIT;
        uint32_t memory_type = find_vulkan_memory_type(
            physical_device,
            memories[m].memory_type_bits,
            required_flags);
        if (memory_type == UINT32_MAX && !memories[m].needs_host_map) {
            memory_type = find_vulkan_memory_type(
                physical_device,
                memories[m].memory_type_bits,
                0);
        }
        if (memory_type == UINT32_MAX) return -ENOTSUP;
        memories[m].memory_type_index = memory_type;
        VkMemoryAllocateInfo mai = {
            .sType = VK_STRUCTURE_TYPE_MEMORY_ALLOCATE_INFO,
            .allocationSize = (VkDeviceSize)memories[m].allocation_size,
            .memoryTypeIndex = memory_type,
        };
        VkResult rc = vkAllocateMemory(device, &mai, NULL, &memories[m].memory);
        if (rc != VK_SUCCESS) return -ENOMEM;
        if (memories[m].needs_host_map) {
            rc = vkMapMemory(device, memories[m].memory, 0,
                             (VkDeviceSize)memories[m].allocation_size, 0,
                             &memories[m].map);
            if (rc != VK_SUCCESS || !memories[m].map) return -EIO;
        }
    }
    for (size_t i = 0; i < *image_count; ++i) {
        VulkanDispatchImageObject *image = &images[i];
        VulkanDispatchImageMemoryObject *memory = &memories[image->memory_object_index];
        uint64_t fd_offset_u64 = 0;
        off_t fd_offset = 0;
        if (checked_u64_add3(memory->external_offset,
                             (uint64_t)image->memory_offset,
                             0,
                             &fd_offset_u64) != 0 ||
            checked_u64_to_off_t(fd_offset_u64, &fd_offset) != 0) {
            return -EOVERFLOW;
        }
        if (image->memory_offset > (VkDeviceSize)memory->allocation_size ||
            image->memory_size > (VkDeviceSize)memory->allocation_size - image->memory_offset) {
            return -ERANGE;
        }
        VkResult rc = vkBindImageMemory(device, image->image,
                                        memory->memory, image->memory_offset);
        if (rc != VK_SUCCESS) return -EINVAL;
        if (image->requires_staging) {
            int brc = create_vulkan_buffer_with_usage(
                physical_device,
                device,
                (size_t)image->memory_size,
                VK_BUFFER_USAGE_TRANSFER_SRC_BIT | VK_BUFFER_USAGE_TRANSFER_DST_BIT,
                NULL,
                &image->staging);
            if (brc != 0) return brc;
            if (read_fd_exact(memory->fd,
                              image->staging.map,
                              (size_t)image->memory_size,
                              fd_offset) != 0) {
                return -EIO;
            }
        } else {
            if (!memory->map) return -EIO;
            if (read_fd_exact(memory->fd,
                              (unsigned char *)memory->map + image->memory_offset,
                              (size_t)image->memory_size,
                              fd_offset) != 0) {
                return -EIO;
            }
        }
    }
    for (size_t i = 0; i < object_tables->image_view_count; ++i) {
        const PdockerGpuVulkanDispatchV5ImageViewEntry *src = &object_tables->image_views[i];
        if (src->image_index >= *image_count) return -EPROTO;
        if (*view_count >= PDOCKER_GPU_MAX_VULKAN_BINDINGS) return -E2BIG;
        VulkanDispatchImageViewObject *dst = &views[(*view_count)++];
        memset(dst, 0, sizeof(*dst));
        dst->view_id = src->view_id;
        dst->source_index = (uint32_t)i;
        dst->image_index = src->image_index;
        dst->range = (VkImageSubresourceRange){
            .aspectMask = (VkImageAspectFlags)src->aspect_mask,
            .baseMipLevel = src->base_mip_level,
            .levelCount = src->level_count,
            .baseArrayLayer = src->base_array_layer,
            .layerCount = src->layer_count,
        };
        VkImageViewCreateInfo ivci = {
            .sType = VK_STRUCTURE_TYPE_IMAGE_VIEW_CREATE_INFO,
            .viewType = (VkImageViewType)src->view_type,
            .image = images[src->image_index].image,
            .format = (VkFormat)src->format,
            .components = {
                .r = (VkComponentSwizzle)src->component_r,
                .g = (VkComponentSwizzle)src->component_g,
                .b = (VkComponentSwizzle)src->component_b,
                .a = (VkComponentSwizzle)src->component_a,
            },
            .subresourceRange = dst->range,
        };
        VkResult rc = vkCreateImageView(device, &ivci, NULL, &dst->view);
        if (rc != VK_SUCCESS) return -EIO;
    }
    for (size_t i = 0; i < object_tables->sampler_count; ++i) {
        const PdockerGpuVulkanDispatchV5SamplerEntry *src = &object_tables->samplers[i];
        if (*sampler_count >= PDOCKER_GPU_MAX_VULKAN_BINDINGS) return -E2BIG;
        VulkanDispatchSamplerObject *dst = &samplers[(*sampler_count)++];
        memset(dst, 0, sizeof(*dst));
        dst->sampler_id = src->sampler_id;
        dst->source_index = (uint32_t)i;
        VkSamplerCreateInfo sci = {
            .sType = VK_STRUCTURE_TYPE_SAMPLER_CREATE_INFO,
            .magFilter = (VkFilter)src->mag_filter,
            .minFilter = (VkFilter)src->min_filter,
            .mipmapMode = (VkSamplerMipmapMode)src->mipmap_mode,
            .addressModeU = (VkSamplerAddressMode)src->address_mode_u,
            .addressModeV = (VkSamplerAddressMode)src->address_mode_v,
            .addressModeW = (VkSamplerAddressMode)src->address_mode_w,
            .mipLodBias = float_from_u32_bits(src->mip_lod_bias_bits),
            .anisotropyEnable = src->anisotropy_enable,
            .maxAnisotropy = float_from_u32_bits(src->max_anisotropy_bits),
            .compareEnable = src->compare_enable,
            .compareOp = (VkCompareOp)src->compare_op,
            .minLod = float_from_u32_bits(src->min_lod_bits),
            .maxLod = float_from_u32_bits(src->max_lod_bits),
            .borderColor = (VkBorderColor)src->border_color,
            .unnormalizedCoordinates = src->unnormalized_coordinates,
        };
        VkResult rc = vkCreateSampler(device, &sci, NULL, &dst->sampler);
        if (rc != VK_SUCCESS) return -EIO;
    }
    for (size_t i = 0; i < image_descriptor_count; ++i) {
        const VulkanDispatchImageDescriptor *d = &image_descriptors[i];
        VkDescriptorType descriptor_type = VK_DESCRIPTOR_TYPE_MAX_ENUM;
        if (vulkan_dispatch_image_descriptor_type_from_api(d->api_descriptor_type,
                                                           &descriptor_type) != 0) {
            return -EOPNOTSUPP;
        }
        if (descriptor_type == VK_DESCRIPTOR_TYPE_INPUT_ATTACHMENT ||
            !vulkan_image_descriptor_layout_valid(descriptor_type, d->image_layout)) {
            return -EOPNOTSUPP;
        }
        if ((d->access_flags & PDOCKER_GPU_V5_ACCESS_WRITE) &&
            descriptor_type != VK_DESCRIPTOR_TYPE_STORAGE_IMAGE) {
            return -EPROTO;
        }
        if (d->image_view_index != PDOCKER_GPU_V5_DESCRIPTOR_OBJECT_NONE) {
            if (d->image_view_index >= *view_count) return -EPROTO;
            if (d->resource_id != 0 &&
                d->resource_id != views[d->image_view_index].view_id) {
                return -EPROTO;
            }
            uint32_t image_index = views[d->image_view_index].image_index;
            if (image_index >= *image_count) return -EPROTO;
            const PdockerGpuVulkanDispatchV5ImageEntry *src_image =
                &object_tables->images[images[image_index].source_index];
            VkImageUsageFlags required_usage =
                vulkan_required_usage_for_image_descriptor(descriptor_type);
            if (required_usage && !(src_image->usage & required_usage)) {
                return -EPROTO;
            }
            if (images[image_index].descriptor_layout_seen &&
                images[image_index].descriptor_layout != d->image_layout) {
                return -EOPNOTSUPP;
            }
            if (images[image_index].copy_aspect_mask &&
                images[image_index].copy_aspect_mask != views[d->image_view_index].range.aspectMask) {
                return -EOPNOTSUPP;
            }
            if (images[image_index].requires_staging) {
                const VkImageSubresourceRange *range =
                    &views[d->image_view_index].range;
                if (range->aspectMask != VK_IMAGE_ASPECT_COLOR_BIT ||
                    range->levelCount == 0 ||
                    range->layerCount == 0 ||
                    range->baseMipLevel >= images[image_index].mip_levels ||
                    range->levelCount >
                        images[image_index].mip_levels - range->baseMipLevel ||
                    range->baseArrayLayer >= images[image_index].array_layers ||
                    range->layerCount >
                        images[image_index].array_layers - range->baseArrayLayer) {
                    return -ENOTSUP;
                }
                if (images[image_index].copy_level_count &&
                    (images[image_index].copy_base_mip != range->baseMipLevel ||
                     images[image_index].copy_level_count != range->levelCount ||
                     images[image_index].copy_base_layer != range->baseArrayLayer ||
                     images[image_index].copy_layer_count != range->layerCount)) {
                    return -EOPNOTSUPP;
                }
                images[image_index].copy_base_mip = range->baseMipLevel;
                images[image_index].copy_level_count = range->levelCount;
                images[image_index].copy_base_layer = range->baseArrayLayer;
                images[image_index].copy_layer_count = range->layerCount;
            }
            images[image_index].copy_aspect_mask =
                views[d->image_view_index].range.aspectMask;
            images[image_index].descriptor_layout = d->image_layout;
            images[image_index].descriptor_layout_seen = 1;
            if (d->access_flags & PDOCKER_GPU_V5_ACCESS_WRITE) {
                images[image_index].writeback_needed = 1;
            }
        }
        if (d->sampler_index != PDOCKER_GPU_V5_DESCRIPTOR_OBJECT_NONE &&
            d->sampler_index >= *sampler_count) {
            return -EPROTO;
        }
        if (d->sampler_index != PDOCKER_GPU_V5_DESCRIPTOR_OBJECT_NONE &&
            d->resource_id != 0 &&
            !vulkan_descriptor_type_requires_image_view(descriptor_type) &&
            d->resource_id != samplers[d->sampler_index].sampler_id) {
            return -EPROTO;
        }
    }
    return 0;
}

static void destroy_strict_vulkan_object_graph(
        VkDevice device,
        VulkanStrictMemoryObject *memories,
        size_t memory_count,
        VulkanStrictBufferObject *buffers,
        size_t buffer_count) {
    if (buffers) {
        for (size_t i = 0; i < buffer_count; ++i) {
            if (buffers[i].staging_map) vkUnmapMemory(device, buffers[i].staging_memory);
            if (buffers[i].staging_buffer) vkDestroyBuffer(device, buffers[i].staging_buffer, NULL);
            if (buffers[i].staging_memory) vkFreeMemory(device, buffers[i].staging_memory, NULL);
            if (buffers[i].buffer) vkDestroyBuffer(device, buffers[i].buffer, NULL);
            memset(&buffers[i], 0, sizeof(buffers[i]));
        }
    }
    if (memories) {
        for (size_t i = 0; i < memory_count; ++i) {
            if (memories[i].map) vkUnmapMemory(device, memories[i].memory);
            if (memories[i].memory) vkFreeMemory(device, memories[i].memory, NULL);
            memset(&memories[i], 0, sizeof(memories[i]));
        }
    }
}

static int create_strict_vulkan_object_graph(
        VkPhysicalDevice physical_device,
        VkDevice device,
        const int *buffer_fds,
        const VulkanDispatchBinding *bindings,
        size_t binding_count,
        const uint8_t *active_bindings,
        const uint8_t *binding_read_needed,
        const uint8_t *binding_write_needed,
        VulkanStrictMemoryObject *memories,
        size_t *memory_count,
        VulkanStrictBufferObject *buffers,
        size_t *buffer_count,
        VulkanVectorBuffer **vk_buffers,
        int device_local_staged,
        VulkanStrictGraphTiming *timing) {
    if (!buffer_fds || !bindings || !active_bindings || !binding_read_needed ||
        !binding_write_needed || !memories || !memory_count || !buffers ||
        !buffer_count || !vk_buffers) {
        return -EINVAL;
    }
    *memory_count = 0;
    *buffer_count = 0;
    for (size_t i = 0; i < binding_count; ++i) {
        if (!active_bindings[i]) continue;
        if (bindings[i].api_memory_id == 0 || bindings[i].api_buffer_id == 0 ||
            bindings[i].api_buffer_size == 0 || bindings[i].api_memory_size == 0 ||
            bindings[i].api_memory_offset < 0 || bindings[i].api_offset < 0 ||
            (uint64_t)bindings[i].api_memory_offset + (uint64_t)bindings[i].api_buffer_size >
                (uint64_t)bindings[i].api_memory_size ||
            (uint64_t)bindings[i].api_offset + (uint64_t)bindings[i].size >
                (uint64_t)bindings[i].api_buffer_size) {
            return -EINVAL;
        }
        int mem_index = find_strict_memory_object(memories, *memory_count, bindings[i].api_memory_id);
        if (mem_index < 0) {
            if (*memory_count >= PDOCKER_GPU_MAX_VULKAN_BINDINGS) return -E2BIG;
            mem_index = (int)(*memory_count)++;
            memories[mem_index].memory_id = bindings[i].api_memory_id;
            memories[mem_index].fd = buffer_fds[i];
            memories[mem_index].size = bindings[i].api_memory_size;
            memories[mem_index].memory_type_bits = UINT32_MAX;
        } else {
            if (memories[mem_index].size < bindings[i].api_memory_size) {
                memories[mem_index].size = bindings[i].api_memory_size;
            }
        }

        int buffer_index = find_strict_buffer_object(buffers, *buffer_count, bindings[i].api_buffer_id);
        if (buffer_index < 0) {
            if (*buffer_count >= PDOCKER_GPU_MAX_VULKAN_BINDINGS) return -E2BIG;
            buffer_index = (int)(*buffer_count)++;
            buffers[buffer_index].buffer_id = bindings[i].api_buffer_id;
            buffers[buffer_index].memory_id = bindings[i].api_memory_id;
            buffers[buffer_index].memory_index = (size_t)mem_index;
            buffers[buffer_index].memory_offset = (VkDeviceSize)bindings[i].api_memory_offset;
            buffers[buffer_index].staging_base = SIZE_MAX;
            buffers[buffer_index].staging_end = 0;
            VkBufferCreateInfo bci = {
                .sType = VK_STRUCTURE_TYPE_BUFFER_CREATE_INFO,
                .size = (VkDeviceSize)bindings[i].api_buffer_size,
                .usage = VK_BUFFER_USAGE_STORAGE_BUFFER_BIT |
                         VK_BUFFER_USAGE_TRANSFER_SRC_BIT |
                         VK_BUFFER_USAGE_TRANSFER_DST_BIT,
                .sharingMode = VK_SHARING_MODE_EXCLUSIVE,
            };
            double op_start = now_ms();
            VkResult rc = vkCreateBuffer(device, &bci, NULL, &buffers[buffer_index].buffer);
            if (timing) {
                timing->create_buffer_ms += now_ms() - op_start;
                timing->created_buffer_bytes += bindings[i].api_buffer_size;
            }
            if (rc != VK_SUCCESS) return -EIO;
            op_start = now_ms();
            vkGetBufferMemoryRequirements(device,
                                          buffers[buffer_index].buffer,
                                          &buffers[buffer_index].requirements);
            if (timing) timing->get_requirements_ms += now_ms() - op_start;
            memories[mem_index].memory_type_bits &= buffers[buffer_index].requirements.memoryTypeBits;
            if ((buffers[buffer_index].memory_offset % buffers[buffer_index].requirements.alignment) != 0) {
                return -EINVAL;
            }
            uint64_t required_end =
                (uint64_t)buffers[buffer_index].memory_offset +
                (uint64_t)buffers[buffer_index].requirements.size;
            if (required_end > memories[mem_index].size) {
                memories[mem_index].size = (size_t)required_end;
            }
        } else if (buffers[buffer_index].memory_id != bindings[i].api_memory_id ||
                   buffers[buffer_index].memory_offset != (VkDeviceSize)bindings[i].api_memory_offset) {
            return -EINVAL;
        }
        if (binding_read_needed[i] || binding_write_needed[i]) {
            const uint64_t range_start = (uint64_t)bindings[i].api_offset;
            const uint64_t range_end = range_start + (uint64_t)bindings[i].size;
            if (range_end > (uint64_t)SIZE_MAX) return -EOVERFLOW;
            if (range_start < buffers[buffer_index].staging_base) {
                buffers[buffer_index].staging_base = (size_t)range_start;
            }
            if (range_end > buffers[buffer_index].staging_end) {
                buffers[buffer_index].staging_end = (size_t)range_end;
            }
        }
    }

    for (size_t m = 0; m < *memory_count; ++m) {
        uint32_t memory_type = find_vulkan_memory_type(
            physical_device,
            memories[m].memory_type_bits,
            device_local_staged
                ? VK_MEMORY_PROPERTY_DEVICE_LOCAL_BIT
                : (VK_MEMORY_PROPERTY_HOST_VISIBLE_BIT | VK_MEMORY_PROPERTY_HOST_COHERENT_BIT));
        if (memory_type == UINT32_MAX && device_local_staged) {
            /*
             * Device-local staging is a correctness/performance probe, not a
             * semantic requirement.  Some Android implementations expose only
             * unified host-visible memory for storage buffers; in that case
             * strict passthrough must keep working and simply fall back to the
             * coherent host-visible object graph.
             */
            memory_type = find_vulkan_memory_type(
                physical_device,
                memories[m].memory_type_bits,
                VK_MEMORY_PROPERTY_HOST_VISIBLE_BIT | VK_MEMORY_PROPERTY_HOST_COHERENT_BIT);
            memories[m].device_local_staged = 0;
        } else {
            memories[m].device_local_staged = device_local_staged ? 1 : 0;
        }
        if (memory_type == UINT32_MAX) return -ENOTSUP;
        memories[m].memory_type_index = memory_type;
        VkMemoryAllocateInfo mai = {
            .sType = VK_STRUCTURE_TYPE_MEMORY_ALLOCATE_INFO,
            .allocationSize = (VkDeviceSize)memories[m].size,
            .memoryTypeIndex = memory_type,
        };
        double op_start = now_ms();
        VkResult rc = vkAllocateMemory(device, &mai, NULL, &memories[m].memory);
        if (timing) {
            timing->allocate_memory_ms += now_ms() - op_start;
            timing->allocated_memory_bytes += memories[m].size;
        }
        if (rc != VK_SUCCESS) return -ENOMEM;
        if (!memories[m].device_local_staged) {
            op_start = now_ms();
            rc = vkMapMemory(device, memories[m].memory, 0, (VkDeviceSize)memories[m].size, 0, &memories[m].map);
            if (timing) {
                timing->map_memory_ms += now_ms() - op_start;
                timing->mapped_memory_bytes += memories[m].size;
            }
            if (rc != VK_SUCCESS || !memories[m].map) return -EIO;
        }
    }

    for (size_t b = 0; b < *buffer_count; ++b) {
        VulkanStrictMemoryObject *memory = &memories[buffers[b].memory_index];
        double op_start = now_ms();
        VkResult rc = vkBindBufferMemory(device, buffers[b].buffer, memory->memory, buffers[b].memory_offset);
        if (timing) timing->bind_buffer_ms += now_ms() - op_start;
        if (rc != VK_SUCCESS) return -EINVAL;
        if (memory->device_local_staged) {
            /*
             * The staging object is not visible to shaders, so it does not
             * need to mirror the whole VkBuffer coordinate space.  Strict API
             * identity is kept by the device-local buffer/memory pair; staging
             * is only a transfer endpoint.  Keep only the union of descriptor
             * ranges that are actually uploaded or downloaded, otherwise
             * llama's multi-GiB buffers get duplicated and the executor can be
             * killed before the correctness gate is even reached.
             */
            if (buffers[b].staging_base != SIZE_MAX &&
                buffers[b].staging_end > buffers[b].staging_base) {
                VkDeviceSize buffer_size =
                    (VkDeviceSize)(buffers[b].staging_end - buffers[b].staging_base);
                VkBufferCreateInfo sbci = {
                    .sType = VK_STRUCTURE_TYPE_BUFFER_CREATE_INFO,
                    .size = buffer_size,
                    .usage = VK_BUFFER_USAGE_TRANSFER_SRC_BIT | VK_BUFFER_USAGE_TRANSFER_DST_BIT,
                    .sharingMode = VK_SHARING_MODE_EXCLUSIVE,
                };
                op_start = now_ms();
                rc = vkCreateBuffer(device, &sbci, NULL, &buffers[b].staging_buffer);
                if (timing) {
                    timing->staging_create_buffer_ms += now_ms() - op_start;
                    timing->staging_buffer_bytes += (size_t)buffer_size;
                }
                if (rc != VK_SUCCESS) return -EIO;
                VkMemoryRequirements staging_req;
                op_start = now_ms();
                vkGetBufferMemoryRequirements(device, buffers[b].staging_buffer, &staging_req);
                if (timing) timing->staging_get_requirements_ms += now_ms() - op_start;
                uint32_t staging_type = find_vulkan_memory_type(
                    physical_device,
                    staging_req.memoryTypeBits,
                    VK_MEMORY_PROPERTY_HOST_VISIBLE_BIT | VK_MEMORY_PROPERTY_HOST_COHERENT_BIT);
                if (staging_type == UINT32_MAX) return -ENOTSUP;
                VkMemoryAllocateInfo smai = {
                    .sType = VK_STRUCTURE_TYPE_MEMORY_ALLOCATE_INFO,
                    .allocationSize = staging_req.size,
                    .memoryTypeIndex = staging_type,
                };
                op_start = now_ms();
                rc = vkAllocateMemory(device, &smai, NULL, &buffers[b].staging_memory);
                if (timing) timing->staging_allocate_memory_ms += now_ms() - op_start;
                if (rc != VK_SUCCESS) return -ENOMEM;
                op_start = now_ms();
                rc = vkBindBufferMemory(device, buffers[b].staging_buffer, buffers[b].staging_memory, 0);
                if (timing) timing->staging_bind_buffer_ms += now_ms() - op_start;
                if (rc != VK_SUCCESS) return -EINVAL;
                op_start = now_ms();
                rc = vkMapMemory(device, buffers[b].staging_memory, 0, staging_req.size, 0, &buffers[b].staging_map);
                if (timing) timing->staging_map_memory_ms += now_ms() - op_start;
                if (rc != VK_SUCCESS || !buffers[b].staging_map) return -EIO;
                buffers[b].staging_size = (size_t)buffer_size;
            }
        }
        buffers[b].view.buffer = buffers[b].buffer;
        buffers[b].view.memory = memory->memory;
        buffers[b].view.staging_buffer = buffers[b].staging_buffer;
        buffers[b].view.map = memory->device_local_staged ? buffers[b].staging_map : memory->map;
        buffers[b].view.size = memory->device_local_staged ? buffers[b].staging_size : memory->size;
        buffers[b].view.staging_base =
            memory->device_local_staged && buffers[b].staging_base != SIZE_MAX
                ? buffers[b].staging_base
                : 0;
        buffers[b].view.device_local_staged = memory->device_local_staged;
    }
    for (size_t i = 0; i < binding_count; ++i) {
        if (!active_bindings[i]) continue;
        int buffer_index = find_strict_buffer_object(buffers, *buffer_count, bindings[i].api_buffer_id);
        if (buffer_index < 0) return -EINVAL;
        VulkanStrictMemoryObject *memory = &memories[buffers[buffer_index].memory_index];
        uint64_t descriptor_absolute =
            (uint64_t)bindings[i].api_memory_offset + (uint64_t)bindings[i].api_offset;
        if (!binding_read_needed[i]) {
            vk_buffers[i] = &buffers[buffer_index].view;
            continue;
        }
        size_t upload_offset = (size_t)descriptor_absolute;
        if (memory->device_local_staged) {
            if (vulkan_vector_staging_offset(&buffers[buffer_index].view,
                                             (size_t)bindings[i].api_offset,
                                             bindings[i].size,
                                             &upload_offset) != 0) return -EINVAL;
        } else if (descriptor_absolute + (uint64_t)bindings[i].size > (uint64_t)memory->size) {
            return -EINVAL;
        }
        vk_buffers[i] = &buffers[buffer_index].view;
        double op_start = now_ms();
        if (read_fd_exact(buffer_fds[i],
                          (unsigned char *)vk_buffers[i]->map + upload_offset,
                          bindings[i].size,
                          bindings[i].offset) != 0) {
            return -EIO;
        }
        if (timing) {
            timing->upload_read_ms += now_ms() - op_start;
            timing->upload_read_bytes += bindings[i].size;
        }
    }
    return 0;
}

static int validate_strict_vulkan_binding_contract(
        const VulkanDispatchBinding *bindings,
        size_t binding_count,
        const char **field_name,
        size_t *binding_index) {
    if (!bindings) {
        if (field_name) *field_name = "bindings";
        if (binding_index) *binding_index = 0;
        return -EINVAL;
    }
    for (size_t i = 0; i < binding_count; ++i) {
        const VulkanDispatchBinding *b = &bindings[i];
        const char *field = NULL;
        if (b->offset < 0) {
            field = "offset";
        } else if (b->api_memory_id == 0) {
            field = "api_memory_id";
        } else if (b->api_buffer_id == 0) {
            field = "api_buffer_id";
        } else if (b->api_buffer_size == 0) {
            field = "api_buffer_size";
        } else if (b->api_memory_size == 0) {
            field = "api_memory_size";
        } else if (b->api_memory_offset < 0) {
            field = "api_memory_offset";
        } else if (b->api_offset < 0) {
            field = "api_offset";
        } else {
            const uint64_t memory_offset = (uint64_t)b->api_memory_offset;
            const uint64_t descriptor_offset = (uint64_t)b->api_offset;
            const uint64_t binding_offset = (uint64_t)b->offset;
            const uint64_t buffer_size = (uint64_t)b->api_buffer_size;
            const uint64_t memory_size = (uint64_t)b->api_memory_size;
            const uint64_t binding_size = (uint64_t)b->size;
            const uint64_t descriptor_range = (uint64_t)b->api_range;
            if (descriptor_offset > buffer_size ||
                binding_size > buffer_size - descriptor_offset) {
                field = "api_offset";
            } else if (descriptor_range == 0 ||
                       descriptor_range > buffer_size - descriptor_offset ||
                       binding_size > descriptor_range) {
                field = "api_range";
            } else if (memory_offset > memory_size ||
                       buffer_size > memory_size - memory_offset) {
                field = "api_memory_offset";
            } else if (memory_offset > UINT64_MAX - descriptor_offset ||
                       binding_offset != memory_offset + descriptor_offset) {
                field = "offset";
            }
        }
        if (field) {
            if (field_name) *field_name = field;
            if (binding_index) *binding_index = i;
            return -EINVAL;
        }
    }
    return 0;
}

static int env_truthy(const char *name, int default_value) {
    const char *value = getenv(name);
    if (!value || !value[0]) return default_value;
    if (strcmp(value, "0") == 0 || strcasecmp(value, "false") == 0 ||
        strcasecmp(value, "no") == 0 || strcasecmp(value, "off") == 0) {
        return 0;
    }
    return 1;
}

static int env_int_value(const char *name, int default_value, int min_value, int max_value) {
    const char *value = getenv(name);
    if (!value || !value[0]) return default_value;
    char *end = NULL;
    long parsed = strtol(value, &end, 10);
    if (end == value) return default_value;
    if (parsed < min_value) parsed = min_value;
    if (parsed > max_value) parsed = max_value;
    return (int)parsed;
}

static uint64_t env_timeout_ns(const char *name, int default_ms, int min_ms, int max_ms) {
    int ms = env_int_value(name, default_ms, min_ms, max_ms);
    return (uint64_t)ms * 1000ull * 1000ull;
}

static int strict_vulkan_passthrough_requested(const VulkanDispatchOptions *options) {
    if (options && options->has_strict_passthrough) {
        return options->strict_passthrough;
    }
    return env_truthy("PDOCKER_GPU_STRICT_PASSTHROUGH", 0);
}

static int strict_vulkan_reconciliation_requested(const VulkanDispatchOptions *options) {
    if (options && options->has_strict_reconciliation) {
        return options->strict_reconciliation;
    }
    return env_truthy("PDOCKER_GPU_STRICT_RECONCILIATION", 0);
}

static void apply_vulkan_feature_policy(VulkanRuntime *rt) {
    if (!rt) return;
    if (env_truthy("PDOCKER_VULKAN_DISABLE_8BIT_STORAGE", 0)) {
        rt->physical_storage8.storageBuffer8BitAccess = VK_FALSE;
        rt->physical_storage8.uniformAndStorageBuffer8BitAccess = VK_FALSE;
        rt->physical_storage8.storagePushConstant8 = VK_FALSE;
        rt->physical_float16_int8.shaderInt8 = VK_FALSE;
    }
    if (env_truthy("PDOCKER_VULKAN_DISABLE_16BIT_STORAGE", 0)) {
        rt->physical_storage16.storageBuffer16BitAccess = VK_FALSE;
        rt->physical_storage16.uniformAndStorageBuffer16BitAccess = VK_FALSE;
        rt->physical_storage16.storagePushConstant16 = VK_FALSE;
        rt->physical_storage16.storageInputOutput16 = VK_FALSE;
    }
    if (env_truthy("PDOCKER_VULKAN_DISABLE_SUBGROUP_ARITHMETIC", 0)) {
        rt->subgroup_properties.supportedOperations &= ~VK_SUBGROUP_FEATURE_ARITHMETIC_BIT;
    }
}

static VulkanRuntime effective_vulkan_runtime_for_dispatch(
        const VulkanRuntime *rt,
        const VulkanDispatchOptions *options) {
    VulkanRuntime effective;
    memset(&effective, 0, sizeof(effective));
    if (rt) effective = *rt;
    if (options && options->disable_storage8) {
        effective.physical_storage8.storageBuffer8BitAccess = VK_FALSE;
        effective.physical_storage8.uniformAndStorageBuffer8BitAccess = VK_FALSE;
        effective.physical_storage8.storagePushConstant8 = VK_FALSE;
        effective.physical_float16_int8.shaderInt8 = VK_FALSE;
    }
    if (options && options->disable_storage16) {
        effective.physical_storage16.storageBuffer16BitAccess = VK_FALSE;
        effective.physical_storage16.uniformAndStorageBuffer16BitAccess = VK_FALSE;
        effective.physical_storage16.storagePushConstant16 = VK_FALSE;
        effective.physical_storage16.storageInputOutput16 = VK_FALSE;
    }
    if (options && options->disable_subgroup_arithmetic) {
        effective.subgroup_properties.supportedOperations &= ~VK_SUBGROUP_FEATURE_ARITHMETIC_BIT;
    }
    return effective;
}

static size_t resident_cache_threshold(const VulkanDispatchOptions *options) {
    if (options && options->has_resident_cache_min_bytes) {
        return options->resident_cache_min_bytes;
    }
    const char *value = getenv("PDOCKER_GPU_RESIDENT_CACHE_MIN_BYTES");
    if (value && value[0]) {
        char *end = NULL;
        unsigned long long parsed = strtoull(value, &end, 10);
        if (end && *end == '\0' && parsed > 0) return (size_t)parsed;
    }
    return PDOCKER_GPU_RESIDENT_CACHE_DEFAULT_THRESHOLD;
}

static int resident_cache_key(int fd, dev_t *dev, ino_t *ino) {
    struct stat st;
    if (fstat(fd, &st) != 0) return -errno;
    *dev = st.st_dev;
    *ino = st.st_ino;
    return 0;
}

static int resident_cache_candidate(
        const VulkanDispatchOptions *options,
        int read_only,
        size_t size) {
    if (options && options->has_resident_cache && !options->resident_cache) return 0;
    if (!options || !options->has_resident_cache) {
        if (!env_truthy("PDOCKER_GPU_RESIDENT_CACHE", 1)) return 0;
    }
    /*
     * Product caching must not infer application semantics from fixed binding
     * numbers.  Only use the resident path after the caller has already proven
     * the descriptor is read-only for this dispatch; writable or unknown
     * bindings continue through the coherent upload/download path.
     */
    if (!read_only) return 0;
    return size >= resident_cache_threshold(options);
}

static int strict_readonly_resident_cache_candidate(
        const VulkanDispatchBinding *bindings,
        size_t binding_count,
        const uint8_t *active_bindings,
        const uint8_t *binding_read_needed,
        const uint8_t *binding_write_needed,
        const VulkanDispatchOptions *options,
        size_t index) {
    if (!bindings || !active_bindings || !binding_read_needed || !binding_write_needed ||
        index >= binding_count || !active_bindings[index] ||
        !binding_read_needed[index] || binding_write_needed[index]) {
        return 0;
    }
    const VulkanDispatchBinding *b = &bindings[index];
    if (!resident_cache_candidate(options, 1, b->size)) return 0;
    if (b->api_offset < 0 || b->api_memory_offset < 0 ||
        (uint64_t)b->api_memory_offset + (uint64_t)b->api_offset !=
            (uint64_t)b->offset ||
        (uint64_t)b->api_offset + (uint64_t)b->size > SIZE_MAX) {
        return 0;
    }
    /*
     * This cache intentionally handles only isolated read-only descriptor
     * windows.  If another active binding shares the same strict API object,
     * keep the full object graph path so descriptor aliasing and writable
     * side effects remain API-faithful.
     */
    for (size_t j = 0; j < binding_count; ++j) {
        if (j == index || !active_bindings[j]) continue;
        if (bindings[j].api_memory_id == b->api_memory_id ||
            bindings[j].api_buffer_id == b->api_buffer_id) {
            return 0;
        }
    }
    return 1;
}

static size_t mutable_buffer_cache_max_bytes(void) {
    const char *value = getenv("PDOCKER_GPU_MUTABLE_BUFFER_CACHE_MAX_BYTES");
    if (value && value[0]) {
        char *end = NULL;
        unsigned long long parsed = strtoull(value, &end, 10);
        if (end && *end == '\0') return (size_t)parsed;
    }
    return PDOCKER_GPU_MUTABLE_BUFFER_CACHE_DEFAULT_MAX_BYTES;
}

static int mutable_buffer_cache_candidate_with_max(
        uint32_t binding,
        size_t size,
        int enabled,
        size_t max_bytes) {
    (void)binding;
    if (!enabled) return 0;
    return max_bytes > 0 && size > 0 && size <= max_bytes;
}

static int writeonly_buffer_cache_enabled(void) {
    return env_truthy("PDOCKER_GPU_WRITEONLY_BUFFER_CACHE", 0);
}

static int writeonly_dirty_probe_enabled(void) {
    return env_truthy("PDOCKER_GPU_WRITEONLY_DIRTY_PROBE", 0);
}

static int writeonly_dirty_writeback_enabled(void) {
    /*
     * Dirty writeback is a performance optimization, not a correctness
     * primitive.  The current sentinel/cache implementation can miss
     * input-dependent write sets, so keep it behind an explicit unsafe opt-in.
     */
    if (!env_truthy("PDOCKER_GPU_UNSAFE_DIRTY_WRITEBACK_CACHE", 0)) return 0;
    return env_truthy("PDOCKER_GPU_WRITEONLY_DIRTY_WRITEBACK", 0);
}

